PlotData



Plot.plot({
    x: { label: "Region" },
    y: { label: "Count" },
    marks: [
    Plot.barY(regionCount, { x: "name", y: "value" }),
    Plot.text(regionCount, { x: "name", y: "value", text: "value", dy: -5 })
  ]
})









Inputs.table(regionCount, {
  columns: [
    "name",
    "value"
  ],    
  header: {
    name: "Air Zone Region",
    value: "Count"
  }
})










data = FileAttachment("2025-regions.csv").csv({ typed: true })







d3 = require("d3@7")

regionCount = Array.from(
  d3.rollup(data, v =&gt; v.length, d =&gt; d.selRegionsIDs),
  ([name, value]) =&gt; ({ name, value })
);

viewof bill_length_min = Inputs.range(
  [32, 50], 
  {value: 35, step: 1, label: "Bill length (min):"}
)
viewof islands = Inputs.checkbox(
  ["Torgersen", "Biscoe", "Dream"], 
  { value: ["Torgersen", "Biscoe"], 
    label: "Islands:"
  }
)
















PlotData



Plot.rectY(filtered, 
  Plot.binX(
    {y: "count"}, 
    {x: "body_mass_g", fill: "species", thresholds: 20}
  ))
  .plot({
    facet: {
      data: filtered,
      x: "sex",
      y: "species",
      marginRight: 80
    },
    marks: [
      Plot.frame(),
    ]
  }
)









Inputs.table(filtered)










data = FileAttachment("palmer-penguins.csv").csv({ typed: true })







filtered = data.filter(function(penguin) {
  return bill_length_min &lt; penguin.bill_length_mm &&
         islands.includes(penguin.island);
})
